module multi_16bit (
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);

reg [31:0] product;
reg [4:0] count;
reg [15:0] multiplicand, multiplier;
reg done_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        product <= 32'b0;
        count <= 5'b0;
        multiplicand <= 16'b0;
        multiplier <= 16'b0;
        done_reg <= 1'b0;
    end
    else if (start) begin
        multiplicand <= ain;
        multiplier <= bin;
        count <= 16;
        done_reg <= 1'b0;
    end
    else if (count > 0) begin
        if (multiplier[0]) begin
            product <= product + {16'b0, multiplicand};
        end
        multiplier <= multiplier >> 1;
        count <= count - 1;
        if (count == 1) begin
            done_reg <= 1'b1;
        end
    end
end

assign yout = product;
assign done = done_reg;

endmodule
